import{_ as a,o as s,c as i,a4 as n}from"./chunks/framework.CtnSHCpE.js";const u=JSON.parse('{"title":"zopen framework","description":"","frontmatter":{},"headers":[],"relativePath":"Guides/zopen.md","filePath":"Guides/zopen.md","lastUpdated":1726863195000}'),t={name:"Guides/zopen.md"};function o(l,e,p,r,d,c){return s(),i("div",null,[...e[0]||(e[0]=[n(`<h1 id="zopen-framework" tabindex="-1">zopen framework <a class="header-anchor" href="#zopen-framework" aria-label="Permalink to &quot;zopen framework&quot;">​</a></h1><p>The following is a description of the zopen framework provided in the meta repo. To obtain the latest meta tools, you can clone and set up the environment as follows:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git clone git@github.com:zopencommunity/meta.git</span></span>
<span class="line"><span>cd meta</span></span>
<span class="line"><span>. ./.env</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>Alternatively, you can download meta via <a href="https://github.com/zopencommunity/meta/releases/" target="_blank" rel="noreferrer">here</a></p><h2 id="if-you-are-using-zopen-community" tabindex="-1">If you are using zopen community <a class="header-anchor" href="#if-you-are-using-zopen-community" aria-label="Permalink to &quot;If you are using zopen community&quot;">​</a></h2><h3 id="zopen-init" tabindex="-1">zopen init <a class="header-anchor" href="#zopen-init" aria-label="Permalink to &quot;zopen init&quot;">​</a></h3><p><code>zopen init</code> is used to initialise a zopen community environment. By default, this will create a <code>zopen</code> directory in your <code>$HOME</code> directory as the root filesystem (rootfs). The rootfs holds the various packages, configuration and environment for zopen community packages - removing this directory will revert the system without a trace. A Zopen Community main configuration file is generated in <code>$rootfs/etc/zopen-config</code> - to enable the Zopen Community, this will either need to be sourced after logon to the system or the following line can be added to <code>$HOME/.profile</code> (or .bash_profile or...) to automatically source the Zopen Community configuration file.</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[ </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$rootfs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/etc/zopen-config&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ] &amp;&amp; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $rootfs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/etc/zopen-config</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>It is possible to reinitialize a system using the <code>re-init</code> option - doing so will remove the previous configuration though the rootfs can overlap the old filesystem to reuse installed and/or cached packages for example. Initialisation on a system that has previously had a zopen community configuration should allow some parameters to be copied across, such as Github tokens.</p><h3 id="zopen-update-cacert" tabindex="-1">zopen update-cacert <a class="header-anchor" href="#zopen-update-cacert" aria-label="Permalink to &quot;zopen update-cacert&quot;">​</a></h3><p>To update the cacert.pem file, you can use <code>zopen update-cacert</code>. This will download the latest cacert.pem file <a href="https://curl.se/docs/caextract.html" target="_blank" rel="noreferrer">https://curl.se/docs/caextract.html</a>. This cacert.pem file is then used by other tools such as <code>zopen install</code> and <code>zopen build</code>.</p><h3 id="zopen-install" tabindex="-1">zopen install <a class="header-anchor" href="#zopen-install" aria-label="Permalink to &quot;zopen install&quot;">​</a></h3><p>To download and install the latest software packages, you can use <code>zopen install</code>.</p><h3 id="zopen-list" tabindex="-1">zopen list <a class="header-anchor" href="#zopen-list" aria-label="Permalink to &quot;zopen list&quot;">​</a></h3><p>To list the available packages, specify no parameters or the <code>--list</code> option as follows:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>zopen list</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>To download and install specfic packages, you can specify the packages as a comma seperated list as follows:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>zopen install make,vim</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="zopen-upgrade" tabindex="-1">zopen upgrade <a class="header-anchor" href="#zopen-upgrade" aria-label="Permalink to &quot;zopen upgrade&quot;">​</a></h3><p>To upgrade already installed software packages, you can use <code>zopen upgrade</code>.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>zopen upgrade</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>To upgrade a specific set of packages, you can specify the packages as a comma seperated list as follows:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>zopen upgrade make</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="if-you-are-contributing-to-or-developing-zopen-community" tabindex="-1">If you are contributing to or developing zopen community <a class="header-anchor" href="#if-you-are-contributing-to-or-developing-zopen-community" aria-label="Permalink to &quot;If you are contributing to or developing zopen community&quot;">​</a></h2><h3 id="zopen-build" tabindex="-1">zopen build <a class="header-anchor" href="#zopen-build" aria-label="Permalink to &quot;zopen build&quot;">​</a></h3><p>To build a software package, you can use <code>zopen build</code>.</p><p><code>zopen build</code> requires the files scripts in the project&#39;s root directory:</p><ul><li><code>buildenv</code>, which <code>zopen build</code> will automatically source. If you would like to source another file, you can specify it via the <code>-e</code> option as in: <code>zopen build -e mybuildenv</code></li></ul><p>The <code>buildenv</code> file <em>must</em> set the following environment variables:</p><ul><li><code>ZOPEN_BUILD_LINE</code>: one of DEV or STABLE indicating which build line to build off of.</li><li><code>ZOPEN_DEV_URL</code> or <code>ZOPEN_STABLE_URL</code>: the URL where the source should be pulled from, including the <code>package.git</code> or <code>package-V.R.M.tar.gz</code> extension</li><li><code>ZOPEN_DEV_DEPS</code> or <code>ZOPEN_STABLE_DEPS</code>: a space-separated list of all software dependencies this package has. These packages will automatically be downloaded if they are not present in your <code>$HOME/zopen/prod</code> or <code>$HOME/zopen/boot</code> directories.</li></ul><p>To help gauge the build quality of the port, a <code>zopen_check_results()</code> function needs to be provided inside the buildenv. This function should process the test results and emit a report of the failures, total number of tests, expected number of failures and expected number of tests to stdout as in the following format:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>actualFailures:&lt;numberoffailures&gt;</span></span>
<span class="line"><span>totalTests:&lt;totalnumberoftests&gt;</span></span>
<span class="line"><span>expectedFailures:&lt;expectednumberoffailures&gt;</span></span>
<span class="line"><span>expectedTotalTests:&lt;expectednumberoftests&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>The build will fail to proceed to the install step if <code>totalTests</code> is less than <code>expectedTotalTests</code> or <code>actualFailures</code> is greater than <code>expectedFailures</code>.</p><p>Here is an example implementation of <code>zopen_check_results()</code>:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zopen_check_results</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">chk</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">$1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$2_check</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.log&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">failures</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;.* Test.*in .* Categories Failed&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> \${chk} </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> cut</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39; &#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">totalTests</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;.* Test.*in .* Categories Failed&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> \${chk} </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> cut</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f5</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39; &#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ZZ</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">actualFailures:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$failures</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">totalTests:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$totalTests</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">expectedFailures:0</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">expectedTotalTests:1</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ZZ</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><p><code>zopen build</code> will generate a .env file in the install location with support for environment variables such as PATH, LIBPATH, and MANPATH. To add your own, you can append environment variables by echo&#39;ing them in a function called <code>zopen_append_to_env()</code>.</p><p>After the build is successful, <code>zopen build</code> will install the project to <code>$HOME/zopen/prod/projectname</code>. To perform post-processing on the installed contents, such as modifying hardcoded path contents, you can write a <code>zopen_post_install()</code> function which takes the installed path as the first argument.</p><p>Note that you can choose the fully-qualified environment variables ZOPEN_DEV_URL, ZOPEN_DEV_DEPS and ZOPEN_STABLE_URL, ZOPEN_STABLE_DEPS accordingly if you prefer. See (<a href="https://github.com/zopencommunity/zotsampleport/blob/main/setenv.sh" target="_blank" rel="noreferrer">https://github.com/zopencommunity/zotsampleport/blob/main/setenv.sh</a>) for an example.</p><p>There are several additional environment variables that can be specified to provide finer-grained control of the build process. For details</p><ul><li>Run <code>zopen build -h</code> for a description of all the environment variables</li><li>Read the code: (<a href="https://github.com/zopencommunity/meta/blob/main/bin/zopen-build" target="_blank" rel="noreferrer">https://github.com/zopencommunity/meta/blob/main/bin/zopen-build</a>).</li></ul><p>For a sample port, visit the <a href="https://github.com/zopencommunity/zotsampleport" target="_blank" rel="noreferrer">zotsampleport</a> repo.</p><h4 id="running-zopen-build" tabindex="-1">Running zopen build <a class="header-anchor" href="#running-zopen-build" aria-label="Permalink to &quot;Running zopen build&quot;">​</a></h4><p>Run <code>zopen build</code> from the root directory of the git repo you would like to build. For example, m4:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cd \${HOME}/zopen/dev/m4</span></span>
<span class="line"><span>zopen build</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="zopen-generate" tabindex="-1">zopen generate <a class="header-anchor" href="#zopen-generate" aria-label="Permalink to &quot;zopen generate&quot;">​</a></h3><p>You can generate a zopen template project with <code>zopen generate</code>. It will ask you a series of questions and then generate the zopen file structure, including a <code>buildenv</code> file that will help you get started with your project.</p><h3 id="zopen-importenvs" tabindex="-1">zopen-importenvs <a class="header-anchor" href="#zopen-importenvs" aria-label="Permalink to &quot;zopen-importenvs&quot;">​</a></h3><p>If you want to source the .env files from all of the installed zopen products under the zopen prod and boot directories, then you can use <code>zopen-importenvs</code>.</p><p>Usage of script is: &quot;. ./zopen-importenvs [path to buildenv to fetch dependency]&quot;</p><p>The path to buildenv is optional.</p><p>If the buildenv path is provided, the dependencies from the buildenv file are read and the env is sourced from prod/boot directory. This is useful if you want to have the same environment as zopen build in order to reproduce a problem with the build. Otherwise if the path is not provided then the .env from each project directory in the zopen prod/boot directories are sourced.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span></span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div>`,52)])])}const b=a(t,[["render",o]]);export{u as __pageData,b as default};
